{ // JQAutoComplete -> ASP.NET Core TagHelper // Frontend runtime: Alpine.js v3 + Tailwind CSS [HtmlTargetElement("g-autocomplete")] public class GAutoCompleteTagHelper : GSearchBoxTagHelper { [HtmlAttributeName("api")] public string LegacyApi { get; set; } = ""; [HtmlAttributeName("api-url")] public string LegacyApiUrl { get; set; } = ""; [HtmlAttributeName("display-field")] public string LegacyDisplayField { get; set; } = ""; [HtmlAttributeName("value-field")] public string LegacyValueField { get; set; } = ""; [HtmlAttributeName("target-id")] public string LegacyTargetId { get; set; } = ""; public override void Process(TagHelperContext context, TagHelperOutput output) { if (string.IsNullOrWhiteSpace(ApiUrl)) { ApiUrl = !string.IsNullOrWhiteSpace(LegacyApiUrl) ? LegacyApiUrl : LegacyApi; } if (string.IsNullOrWhiteSpace(DisplayField) && !string.IsNullOrWhiteSpace(LegacyDisplayField)) { DisplayField = LegacyDisplayField; } if (string.IsNullOrWhiteSpace(ValueField) && !string.IsNullOrWhiteSpace(LegacyValueField)) { ValueField = LegacyValueField; } if (string.IsNullOrWhiteSpace(TargetId) && !string.IsNullOrWhiteSpace(LegacyTargetId)) { TargetId = LegacyTargetId; } base.Process(context, output); } }
}


